let aiData = {};
try {
  const r = $input.first().json.candidates[0].content.parts[0].text;
  aiData = JSON.parse(r);
} catch(e) {
  aiData = { erro: 'Falha ao fazer parse do JSON do Gemini' };
}

// Prepara dados booleanos para facilitar o roteamento
const temBugs = aiData.bugs_reportados && aiData.bugs_reportados.length > 0;
const temReclamacao = aiData.reclamacoes_prazos && aiData.reclamacoes_prazos.length > 0;

return [{ json: { ...$input.first().json, ai_extracted: aiData, routing: { temBugs, temReclamacao } } }];
